import{_ as e,o as n,c as s,ae as i}from"./chunks/framework.CDhj6wcg.js";const c=JSON.parse('{"title":"Coding Rules & Conventions","description":"","frontmatter":{},"headers":[],"relativePath":"08-code-rules.md","filePath":"08-code-rules.md"}'),t={name:"08-code-rules.md"};function o(l,a,d,r,p,k){return n(),s("div",null,[...a[0]||(a[0]=[i(`<h1 id="coding-rules-conventions" tabindex="-1">Coding Rules &amp; Conventions <a class="header-anchor" href="#coding-rules-conventions" aria-label="Permalink to &quot;Coding Rules &amp; Conventions&quot;">​</a></h1><blockquote><p>Dokumen ini berisi kumpulan aturan penulisan kode tambahan yang akan terus diperbarui secara bertahap seiring dengan berjalannya development project ini. Semua developer harus mematuhi aturan berikut.</p></blockquote><hr><h2 id="_1-comment-dokumentasi" tabindex="-1">1. Comment &amp; Dokumentasi <a class="header-anchor" href="#_1-comment-dokumentasi" aria-label="Permalink to &quot;1. Comment &amp; Dokumentasi&quot;">​</a></h2><ul><li><strong>DILARANG memakai divider ASCII (<code>======</code>)</strong>: Dilarang merekayasa <em>header</em> / <em>divider</em> komentar menggunakan banyak tanda sama dengan (<code>====================================</code>). Hal ini membuat kode tidak rapi dan memakan banyak tempat visual. Gunakan saja komentar biasa, jdoc, atau Markdown standard bila diperlukan.</li></ul><h2 id="_2-dependency-injection" tabindex="-1">2. Dependency Injection <a class="header-anchor" href="#_2-dependency-injection" aria-label="Permalink to &quot;2. Dependency Injection&quot;">​</a></h2><ul><li><strong>Wajib menggunakan <code>@RequiredArgsConstructor</code></strong>: Untuk dependency injection (field private final), dilarang menulis constructor manual. Gunakan annotasi <code>@RequiredArgsConstructor</code> dari Lombok untuk menjaga kode tetap ringkas dan konsisten (Constructor-based Injection).</li><li><strong>Gunakan <code>private final</code></strong>: Semua service/repository yang dipanggil di class lain harus di-set sebagai <code>private final</code> agar otomatis masuk ke constructor Lombok.</li></ul><h2 id="_3-formatting" tabindex="-1">3. Formatting <a class="header-anchor" href="#_3-formatting" aria-label="Permalink to &quot;3. Formatting&quot;">​</a></h2><ul><li><strong>Satu Baris Kosong Antar Fungsi</strong>: Pastikan ada <strong>satu baris kosong</strong> (blank line) di antara penutup fungsi <code>}</code> dan pembuka fungsi berikutnya. Hal ini untuk menjaga keterbacaan (readability) kode.</li></ul><h2 id="_4-controller-documentation" tabindex="-1">4. Controller Documentation <a class="header-anchor" href="#_4-controller-documentation" aria-label="Permalink to &quot;4. Controller Documentation&quot;">​</a></h2><ul><li><strong>Wajib menggunakan Javadoc Comment pada setiap Mapping Method</strong>: Setiap method di Controller yang memiliki annotasi <code>@GetMapping</code>, <code>@PostMapping</code>, dsb, wajib memiliki komentar Javadoc di atasnya.</li><li><strong>Format</strong>: Baris pertama berisi <code>[METHOD] [URL]</code>, baris kedua berisi deskripsi singkat fungsi tersebut.<div class="language-java vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/**</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> * PUT /api/v1/modules/{id}</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> * Updates name and description only. Slug is immutable.</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> */</span></span></code></pre></div></li></ul><h2 id="_5-api-response-format" tabindex="-1">5. API Response Format <a class="header-anchor" href="#_5-api-response-format" aria-label="Permalink to &quot;5. API Response Format&quot;">​</a></h2><ul><li><strong>Wajib menggunakan <code>ResData&lt;T&gt;</code></strong>: Semua endpoint API wajib mengembalikan objek <code>ResponseEntity&lt;ResData&lt;T&gt;&gt;</code> dimana T adalah DTO.</li><li><strong>Struktur Standard</strong>: Response harus memiliki 3 field utama: <ul><li><code>status</code> (String): Label status, yaitu <code>&quot;success&quot;</code> (untuk 2xx) atau <code>&quot;error&quot;</code> (untuk 4xx/5xx).</li><li><code>message</code> (String): Pesan deskriptif.</li><li><code>data</code> (T): Objek data utama atau <code>null</code>. Field ini berisi DTO yang sesuai dengan operasi.</li></ul></li><li><strong>Cara Pakai</strong>: <ul><li>GET list: <code>ResponseEntity.ok(ResData.of(listDto))</code></li><li>GET single: <code>ResponseEntity.ok(ResData.of(dto))</code></li><li>POST: <code>ResponseEntity.status(HttpStatus.CREATED).body(ResData.created(dto))</code></li><li>PUT: <code>ResponseEntity.ok(ResData.of(dto))</code></li><li>DELETE: <code>service.delete(id); return ResponseEntity.ok(ResData.deleted());</code></li></ul></li><li><strong>Kelebihan</strong>: Fokus pada kejelasan status operasional tanpa redundansi kode angka di dalam body JSON (karena kode angka sudah ada di HTTP Header).</li></ul><h2 id="_6-comment-style-untuk-non-controller-rest" tabindex="-1">6. Comment Style untuk Non-Controller REST <a class="header-anchor" href="#_6-comment-style-untuk-non-controller-rest" aria-label="Permalink to &quot;6. Comment Style untuk Non-Controller REST&quot;">​</a></h2><ul><li><strong>Service Class</strong>: Gunakan komentar Javadoc pada public method yang berisi logika bisnis. Format: baris pertama menjelaskan apa yang dilakukan method, baris kedua menjelaskan parameter khusus atau catatan penting (misalnya validasi atau side-effect).<div class="language-java vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/**</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> * Creates a new user with encrypted password.</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> * Throws IllegalArgumentException if username already exists.</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> */</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">public</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> UserResponse </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">create</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(CreateUserRequest request) { ... }</span></span></code></pre></div></li><li><strong>Repository Interface</strong>: Dilarang menambahkan Javadoc pada method bawaan Spring Data JPA (findById, findAll, save, delete). Cukup tambahkan komentar pada custom query method (misalnya <code>@Query</code> atau method dengan nama yang tidak standar).<div class="language-java vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Finds all active tokens for a given username</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">List</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Token</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> findAllByUsername</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(String username);</span></span></code></pre></div></li><li><strong>DTO Class</strong>: Tambahkan Javadoc pada class level yang menjelaskan kapan DTO ini dipakai. Field-level comment hanya diperlukan jika nama field tidak cukup menjelaskan maksudnya.<div class="language-java vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/**</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> * Response DTO for user listing endpoints.</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> * Contains flattened role data to avoid circular reference.</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> */</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">public</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> class</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> UserResponse</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { ... }</span></span></code></pre></div></li><li><strong>Model/Entity Class</strong>: Tidak wajib diberi Javadoc jika nama tabel dan field sudah self-explanatory. Tambahkan komentar hanya pada field yang memiliki logika khusus (misalnya <code>@PrePersist</code>, computed field, atau relasi yang tidak umum).</li></ul><p><em>(Aturan-aturan lainnya akan ditambahkan di sini...)</em></p>`,16)])])}const h=e(t,[["render",o]]);export{c as __pageData,h as default};
